+fn aggregate_scores(a: f64, b: f64, aggregate: &[u8]) -> f64 {
+    if eq_ascii_ci(aggregate, b"MIN") {
+        a.min(b)
+    } else if eq_ascii_ci(aggregate, b"MAX") {
+        a.max(b)
+    } else {
+        // Default is SUM
+        a + b
+    }
+}
